export function getExerciseVideoUrl(name) {
  if (!name) return null;
  const norm = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  
  // 1. Direct match
  if (exerciseVideos[norm]) {
    return exerciseVideos[norm];
  }
  
  // 2. Partial match (key inside normalized name)
  for (const [key, url] of Object.entries(exerciseVideos)) {
    if (key.length > 3 && norm.includes(key)) {
      return url;
    }
  }
  
  // 3. Inverse partial match (normalized name inside key)
  for (const [key, url] of Object.entries(exerciseVideos)) {
    if (norm.length > 3 && key.includes(norm)) {
      return url;
    }
  }
  
  // 4. Keyword matching
  const words = name.toLowerCase().split(/\s+/).filter(w => w.length > 3);
  for (const word of words) {
    const wordNorm = word.replace(/[^a-z0-9]/g, '');
    if (exerciseVideos[wordNorm]) {
      return exerciseVideos[wordNorm];
    }
  }
  
  return null;
}
